#include<bits/stdc++.h>
using namespace std;

char a[1001][1001];
int n, m;
int dx[4] = {0, 1, 0, -1};
int dy[4] = {1, 0, -1, 0};


void dfs(int x, int y) {
    a[x][y] = '.';
    for (int i = 0; i < 4; i++) {
        int nx = x + dx[i];
        int ny = y + dy[i];
        if (nx >= 1 && nx <= n && ny >= 1 && ny <= m) {
            if (a[nx][ny] == '#') {
                dfs(nx, ny);
            }
        }
    }
}


bool check(int x, int y) {
    if (x + 1 > n || y + 1 > m) return true;
    int c = 0;
    if (a[x][y] == '#') c++;
    if (a[x+1][y] == '#') c++;
    if (a[x][y+1] == '#') c++;
    if (a[x+1][y+1] == '#') c++;
    return c != 3;
}

int main() {
    cin >> n >> m;
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            cin >> a[i][j];
        }
    }


    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            if (!check(i, j)) {
                cout << "Bad placement.";
                return 0;
            }
        }
    }


    int s = 0;
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= m; j++) {
            if (a[i][j] == '#') {
                s++;
                dfs(i, j);
            }
        }
    }

    cout << "There are " << s << " ships.";
    return 0;
}
